class Solution {
    public int minChanges(int n, int k) {
        if (n == k) return 0;
        String ns = Integer.toBinaryString(n);
        String ks = Integer.toBinaryString(k);
        int count = 0;
        for (int i = 0; i < Math.max(ns.length(), ks.length()); i++) {
            if (i >= ns.length()) {
                if (ks.charAt(i - ns.length()) == '1') count++;
            } else if (i >= ks.length()) {
                if (ns.charAt(i - ks.length()) == '1') count++;
            } else {
                if (ns.charAt(i) != ks.charAt(i)) count++;
            }
        }
        return count;
    }
}
